+                let mut telemetry = AmacStallTelemetry::new(100_000);
+                for elapsed in &observations {
+                    telemetry.record(*elapsed);
+                }
+                assert!(
+                    telemetry.total_stalls <= telemetry.total_calls,
+                    "stalls {} > calls {}",
