+                let snap = telemetry.snapshot();
+                assert!(
+                    snap.recent_window_size <= TELEMETRY_WINDOW_SIZE,
+                    "window {} > capacity {}",
+                    snap.recent_window_size,
+                    TELEMETRY_WINDOW_SIZE,
